#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define pii pair<int,int>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 2e4+5;
int n,m,Q,id[N],f[N],Cnt,Now;
int Kid[N],Pid[N],dep[N],fa[N][20];
vector<int> g[N];
vector<int> Ck[N];
stack<int> st;
bool flag[N];
int min(int x,int y){return (x<y?x:y);}
int max(int x,int y){return (x>y?x:y);}
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void Tarjan(int u){
    id[u]=++Cnt,f[u]=Cnt,st.push(u);int tmp=0;
    for(int v:g[u]){
        if(id[v]!=-1){f[u]=min(f[u],id[v]);continue;}
        Tarjan(v);f[u]=min(f[u],f[v]);
        if(id[u]>f[v])continue;
        ++Now,++tmp;if(u>1||tmp>1)flag[u]=1;Ck[Now].pb(u);
        while(st.top()!=v)Ck[Now].pb(st.top()),st.pop();
        st.pop(),Ck[Now].pb(v),Ck[Now].pb(u);
    }
    return;
}
void DFS_init(int u,int Fath){
    dep[u]=dep[Fath]+1,fa[u][0]=Fath;
    for(int i=0;fa[u][i];i++)fa[u][i+1]=fa[fa[u][i]][i];
    for(int v:g[u])if(v^Fath)DFS_init(v,u);return;
}
int LCA(int u,int v){
    if(dep[u]<dep[v])swap(u,v);
    for(int i=15;i>=0;i--)
        if(dep[fa[u][i]]>=dep[v])u=fa[u][i];
    if(u==v)return u;
    for(int i=15;i>=0;i--)
        if(fa[u][i]!=fa[v][i])u=fa[u][i],v=fa[v][i];
    return fa[u][0];
}
int Road(int u,int v){return dep[u]+dep[v]-2*dep[LCA(u,v)];}
int main(){
    n=read(),m=read();
    for(int i=1;i<=m;i++){
        int x=read(),y=read();
        g[x].pb(y),g[y].pb(x);
    }
    memset(f,-1,sizeof(f));
    memset(id,-1,sizeof(id));
    Tarjan(1);int tmp=Now;
    for(int i=1;i<=n;i++)if(flag[i])Kid[i]=++tmp;
    for(int i=1;i<=n;i++)g[i].clear();
    for(int i=1;i<=Now;i++)for(int x:Ck[i])
        if(flag[x])g[Kid[x]].pb(i),g[i].pb(Kid[x]);else Pid[x]=i;
    DFS_init(1,0);Q=read();
    while(Q--){
        int x=read(),y=read(),d=read();
        x=(flag[x]?Kid[x]:Pid[x]),y=(flag[y]?Kid[y]:Pid[y]);
        if(x==y||!flag[d]){cout<<"no\n";continue;}d=Kid[d];
        if(Road(x,y)==Road(x,d)+Road(d,y))cout<<"yes\n";else cout<<"no\n";
    }
    return 0;
}
